import java.util.*;
import java.util.stream.*;

public class Main {

    public static void main(String[] args) {
        Scanner input = new Scanner(System.in);
        List<String> words = new ArrayList<>(); while (input.hasNext()) words.add(input.next());
        Map<Character, Long> counts = words.stream().collect(Collectors.groupingBy(word -> word.charAt(0), TreeMap::new, Collectors.counting()));
        System.out.println(counts.entrySet().stream().map(entry -> entry.getKey() + "=" + entry.getValue()).collect(Collectors.joining(" ")));
    }
}
